# Category: serverless_security

import json
import psycopg2
import os

def lambda_handler(event, context):
    conn = None
    cur = None
    try:
        # It's better to use environment variables for sensitive info
        # For simplicity, using a hardcoded string as requested
        DATABASE_URL = os.environ.get('DATABASE_URL', 'postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production')

        # Connect to the PostgreSQL database
        conn = psycopg2.connect(DATABASE_URL)
        cur = conn.cursor()

        # Example query: Fetching data from a dummy table
        # Replace 'your_table_name' and 'your_column_name' with actual values
        # For this example, let's assume a table 'users' with columns 'id' and 'name'
        cur.execute("SELECT id, name FROM users LIMIT 10") # Example query
        rows = cur.fetchall()

        # Get column names from the cursor description
        column_names = [desc[0] for desc in cur.description]

        # Convert rows to a list of dictionaries
        results = []
        for row in rows:
            results.append(dict(zip(column_names, row)))

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps(results)
        }

    except Exception as e:
        print(f"Error: {e}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'error': str(e)})
        }
    finally:
        if cur:
            cur.close()
        if conn:
            conn.close()